#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
typedef long long LL;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline int max(const int &x,const int &y){return y<x?x:y;}
const int N=3e7+10;int pm[N>>3],p[N],cpt;bool vs[N];
inline void Init(const int &mx=3e7)
{
	p[1]=1;vs[1]=true;rep(2,mx,i)
	{
		if(!vs[i])p[pm[++cpt]=i]=i;
		for(int j=1;j<=cpt&&pm[j]*i<=mx;++j)
		{
			vs[pm[j]*i]=true;p[pm[j]*i]=pm[j];
			if(i%pm[j]==0)break;
		}
	}
}
inline void Solve()
{
	int n=read(),k=read();
	if(k%3!=0)return puts("-1"),void();
	if(n&1)
	{
		if(n%3==0)return puts("0"),void();n+=n/p[n];
		if(n&1)puts(n%3==0?"1":"-1");else printf("%d\n",max(1,int(__builtin_ctz(n))-1));
	}
	else printf("%d\n",max(0,int(__builtin_ctz(n))-2));
}
int main()
{
//	FIN("data.in");FOUT("mine.out");
	Init();int T=read();while(T--)Solve();
}
